import { useEffect, useState } from 'react';
export function useProjectSearch(query: string) {
  const [results, setResults] = useState<Result[]>([]);
  useEffect(() => {
    const controller = new AbortController();
    fetch(`/api/search?q=${encodeURIComponent(query)}`, { signal: controller.signal })
      .then(r => r.json()).then(setResults);
    return () => controller.abort();
  }, [query]);
  return results;
}

export async function fetchWithRetry(url: string, attempts = 3): Promise<Response> {
  for (let n = 0; n < attempts; n++) {
    const response = await fetch(url);
    if (response.ok) return response;
    if (response.status < 500) throw new Error(`request failed: ${response.status}`);
    await new Promise(resolve => setTimeout(resolve, 2 ** n * 100));
  }
  throw new Error('retry budget exhausted');
}

export class LruCache<V> {
  private values = new Map<string, V>();
  get(key: string): V | undefined { const value = this.values.get(key); if (value !== undefined) { this.values.delete(key); this.values.set(key, value); } return value; }
  set(key: string, value: V) { this.values.delete(key); this.values.set(key, value); if (this.values.size > 100) this.values.delete(this.values.keys().next().value!); }
}

import asyncio
async def request_with_backoff(client, url, attempts=4):
    for attempt in range(attempts):
        try:
            return await client.get(url)
        except TimeoutError:
            if attempt + 1 == attempts:
                raise
            await asyncio.sleep(0.1 * (2 ** attempt))

from math import sqrt
def cosine_similarity(left, right):
    dot = sum(a * b for a, b in zip(left, right))
    left_norm = sqrt(sum(a * a for a in left))
    right_norm = sqrt(sum(b * b for b in right))
    if not left_norm or not right_norm:
        raise ValueError('zero vector')
    return dot / (left_norm * right_norm)

def extract_unique_span(source, anchor, before, after):
    if source.count(anchor) != 1:
        raise ValueError('anchor must occur exactly once')
    lines = source.splitlines()
    line = next(i for i, value in enumerate(lines) if anchor in value)
    return '\n'.join(lines[max(0, line-before):line+after+1])

pub fn batches<T>(items: &[T], size: usize) -> impl Iterator<Item = &[T]> {
    assert!(size > 0);
    items.chunks(size)
}
async fn embed_all(provider: &Provider, texts: &[String]) -> Result<Vec<Vector>> {
    let mut output = Vec::with_capacity(texts.len());
    for batch in batches(texts, 32) { output.extend(provider.embed(batch).await?); }
    Ok(output)
}

use anyhow::{Context, Result};
fn load_dataset(path: &Path) -> Result<Dataset> {
    let bytes = std::fs::read(path).with_context(|| format!("read {}", path.display()))?;
    serde_json::from_slice(&bytes).context("decode benchmark dataset")
}

fn parse_color(input: &str) -> Option<(u8, u8, u8)> {
    let value = input.strip_prefix('#')?;
    Some((u8::from_str_radix(&value[0..2], 16).ok()?, u8::from_str_radix(&value[2..4], 16).ok()?, u8::from_str_radix(&value[4..6], 16).ok()?))
}
